// Login.jsx - Clean
import React, { useState, useContext } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';
import s from './Auth.module.css';

export default function Login() {
  const nav = useNavigate();
  const { login } = useAuth();
  const [form, setForm] = useState({ email: '', password: '' });
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async e => {
    e.preventDefault();
    setError('');
    setLoading(true);
    try {
      await login(form.email, form.password);
      nav('/chat');
    } catch (err) {
      setError(err.response?.data?.detail || 'Invalid email or password.');
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className={s.page}>
      <div className={s.bg1} /><div className={s.bg2} />
      <button onClick={() => nav('/')} className={s.back}>← Back</button>
      <div className={s.card}>
        <div className={s.cardLogo}><img src="/logo.png" alt="Logo" style={{ width: 40 }} /></div>
        <h1 className={s.title}>Welcome back</h1>
        <p className={s.sub}>Sign in to continue</p>
        {error && <div className={s.err}>{error}</div>}
        <form onSubmit={onSubmit} className={s.form}>
          <div className={s.field}><label>Email</label><input className={s.input} type="email" value={form.email} onChange={e => setForm({...form, email: e.target.value})} required /></div>
          <div className={s.field}><label>Password</label><input className={s.input} type="password" value={form.password} onChange={e => setForm({...form, password: e.target.value})} required /></div>
          <button className={s.submit} disabled={loading}>{loading ? 'Signing in...' : 'Sign in →'}</button>
        </form>
        <p className={s.switch}>No account? <Link to="/register" className={s.link}>Create account</Link></p>
      </div>
    </div>
  );
}
